# setup_inventario_v2.ps1 - Modulo 5 WMS
# Ejecutar desde: Descargas\START_ERP\START_ERP\

Write-Host "Instalando Modulo 5 WMS..." -ForegroundColor Cyan

Write-Host "  src/modules/inventory/types/wms.types.ts" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\inventory\types\wms.types.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\inventory\types\wms.types.ts", $text, [System.Text.Encoding]::UTF8)

